const cellKey = ([x, y]: Cell): string => `${x},${y}`;
// bindings: x, y, cellKey = 3
// invocations: template literal interpolation (treat as 0)
// Mass: 3

const NEIGHBOR_OFFSETS = [...8 pairs of 2 constants];
// constants: 16 numeric literals = 16
// bindings: 1 (NEIGHBOR_OFFSETS) = 1
// Mass: 17

const neighborsOf = ([x, y]: Cell): Cell[] =>
  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
// bindings: x, y, dx, dy, neighborsOf = 5
// invocations: map, + (x2) = 6
// loops: 1 (map) = 5
// Mass: 16

const countLiveNeighbors = (cell, liveSet) =>
  neighborsOf(cell).filter((n) => liveSet.has(cellKey(n))).length;
// bindings: cell, liveSet, n, countLiveNeighbors = 4
// invocations: neighborsOf, filter, has, cellKey, .length = 10
// loops: 1 (filter) = 5
// Mass: 19

const isAliveNextGeneration = (cell, liveSet) => {
  const liveNeighborCount = countLiveNeighbors(cell, liveSet);
  const isCurrentlyAlive = liveSet.has(cellKey(cell));
  return liveNeighborCount === 3 || (isCurrentlyAlive && liveNeighborCount === 2);
};
// constants: 3, 2 = 2
// bindings: cell, liveSet, liveNeighborCount, isCurrentlyAlive, isAliveNextGeneration = 5
// invocations: countLiveNeighbors, has, cellKey, ===, ===, ||, && = 14
// Mass: 21

const candidateCellsFor = (liveCells) => {
  const allCandidates = liveCells.flatMap((cell) => [cell, ...neighborsOf(cell)]);
  return [...new Map(allCandidates.map((c) => [cellKey(c), c])).values()];
};
// bindings: liveCells, allCandidates, cell, c, candidateCellsFor = 5
// invocations: flatMap, neighborsOf, Map constructor, map, cellKey, values = 12
// loops: flatMap, map = 10
// Mass: 27

export function nextGeneration(liveCells) {
  const liveSet = new Set(liveCells.map(cellKey));
  return candidateCellsFor(liveCells).filter((cell) => isAliveNextGeneration(cell, liveSet));
}
// bindings: liveCells, liveSet, cell, nextGeneration = 4
// invocations: Set constructor, map, cellKey, candidateCellsFor, filter, isAliveNextGeneration = 12
// loops: map, filter = 10
// Mass: 26

Total Mass: 129
